import React from 'react';
import { NavLink } from 'react-router-dom';
import { useDispatch } from 'react-redux';
import { adminLogout } from '../store/slices/authSlice';

const NAV = [
  { to: '/', icon: '📊', label: 'Dashboard', end: true },
  { to: '/users', icon: '👥', label: 'Users' },
  { to: '/venues', icon: '🏢', label: 'Venues' },
  { to: '/reservations', icon: '📋', label: 'Reservations' },
  { to: '/payments', icon: '💳', label: 'Payments' },
  { to: '/stories', icon: '🎥', label: 'Stories' },
  { to: '/analytics', icon: '📈', label: 'Analytics' },
];

export default function Sidebar() {
  const dispatch = useDispatch();
  return (
    <aside className="w-56 bg-sidebar border-r border-border flex flex-col">
      {/* Logo */}
      <div className="p-5 border-b border-border">
        <div className="flex items-center space-x-2">
          <div className="w-8 h-8 bg-primary rounded-lg flex items-center justify-center">
            <span className="text-white font-bold text-sm">W</span>
          </div>
          <div>
            <p className="font-display font-bold text-white text-sm">Way Out</p>
            <p className="text-xs text-gray-500">Admin Panel</p>
          </div>
        </div>
      </div>

      {/* Nav */}
      <nav className="flex-1 p-3 space-y-1">
        {NAV.map((item) => (
          <NavLink
            key={item.to}
            to={item.to}
            end={item.end}
            className={({ isActive }) =>
              `sidebar-link ${isActive ? 'active' : ''}`
            }
          >
            <span className="text-base">{item.icon}</span>
            <span>{item.label}</span>
          </NavLink>
        ))}
      </nav>

      {/* Logout */}
      <div className="p-3 border-t border-border">
        <button
          onClick={() => dispatch(adminLogout())}
          className="sidebar-link w-full text-red-400 hover:text-red-300 hover:bg-red-500/10"
        >
          <span>🚪</span>
          <span>Logout</span>
        </button>
      </div>
    </aside>
  );
}
